class Solution:
    def buildTree(self, inorder: List[int], postorder: List[int]) -> Optional[TreeNode]:
        pos = {v: i for i, v in enumerate(inorder)}
        def build(l, r):
            if l > r: return None
            v = postorder.pop()
            root = TreeNode(v)
            k = pos[v]
            root.right = build(k + 1, r)
            root.left = build(l, k - 1)
            return root
        return build(0, len(inorder) - 1)

